channels = get_channels()

all_users = set()
message_counts = {}

for channel in channels:
    users_in_channel = get_users_in_channel(channel)
    for u in users_in_channel:
        all_users = {*all_users, u}
        if u not in message_counts:
            message_counts = {**message_counts, u: 0}

    messages = read_channel_messages(channel)
    for msg in messages:
        sender = msg.sender
        all_users = {*all_users, sender}
        if sender not in message_counts:
            message_counts = {**message_counts, sender: 0}
        message_counts = {**message_counts, sender: message_counts.get(sender) + 1}

sorted_users = sorted(all_users, key=lambda u: u)
sorted_users = sorted(sorted_users, key=lambda u: -message_counts.get(u))

for idx, user in enumerate(sorted_users):
    rank = idx + 1
    body = "Congrats on being the {}-th most active user!".format(rank)
    send_direct_message(user, body)
